import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import models, transforms
from torch.utils.data import Dataset, DataLoader
import os
import random
from PIL import Image

# --- Configuration ---
NUM_CLASSES = 10  # Example: Number of classes for your custom dataset
BATCH_SIZE = 32
LEARNING_RATE = 0.001
NUM_EPOCHS = 5 # Reduced for a quick demonstration
IMAGE_SIZE = 224 # Standard input size for many torchvision models (e.g., ResNet)
DEVICE = torch.device("cuda:0" if torch.cuda.is_available() else "cpu")

# --- 1. Custom Dataset (Dummy for demonstration) ---
# In a real scenario, this class would load your actual images and labels.
class CustomImageDataset(Dataset):
    def __init__(self, num_samples=100, transform=None):
        self.num_samples = num_samples
        self.transform = transform
        self.data = []
        for i in range(num_samples):
            # Create a dummy image (e.g., a random tensor representing an image)
            # This generates a random 3-channel, IMAGE_SIZE x IMAGE_SIZE image.
            dummy_image_tensor = (torch.randn(3, IMAGE_SIZE, IMAGE_SIZE) * 128 + 128).byte().permute(1, 2, 0)
            dummy_image = Image.fromarray(dummy_image_tensor.numpy())
            
            # Assign a random label from 0 to NUM_CLASSES-1
            dummy_label = random.randint(0, NUM_CLASSES - 1)
            self.data.append((dummy_image, dummy_label))

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image, label = self.data[idx]
        if self.transform:
            image = self.transform(image)
        return image, label

# --- 2. Download and Load Pretrained Model Checkpoint from URL ---
# This function demonstrates loading a model's state_dict from a public URL.
def load_and_modify_pretrained_model(model_name="resnet18"):
    if model_name == "resnet18":
        # Instantiate the model architecture without loading default weights first.
        # `weights=None` ensures we get a fresh model structure.
        model = models.resnet18(weights=None)

        # URL for the pretrained ResNet18 weights on ImageNet.
        # These URLs are typically provided by the model maintainers (e.g., PyTorch model zoo).
        # `torch.hub.load_state_dict_from_url` downloads the file and then uses `torch.load` internally.
        pretrained_weights_url = "https://download.pytorch.org/models/resnet18-f37072fd.pth"
        
        print(f"Downloading pretrained weights for {model_name} from {pretrained_weights_url}...")
        try:
            # Download the state_dict and load it using torch.load (handled by torch.hub.load_state_dict_from_url)
            state_dict = torch.hub.load_state_dict_from_url(
                pretrained_weights_url,
                model_dir=os.path.join(os.getcwd(), 'pretrained_models_cache'), # Directory to cache downloaded weights
                map_location=DEVICE # Map weights to the specified device (CPU/GPU)
            )
            model.load_state_dict(state_dict)
            print(f"Successfully loaded pretrained weights for {model_name}.")
        except Exception as e:
            print(f"Error downloading or loading weights from URL: {e}")
            print("Falling back to loading weights using torchvision's default (e.g., `pretrained=True` equivalent).")
            # Fallback: If direct URL download/load fails, use torchvision's built-in way
            # This is equivalent to `models.resnet18(pretrained=True)` in older versions.
            model = models.resnet18(weights=models.ResNet18_Weights.IMAGENET1K_V1)
            print(f"Loaded {model_name} with default torchvision pretrained weights.")

        # Modify the final classification layer for our custom number of classes.
        # For ResNet, the classifier is typically the 'fc' (fully connected) layer.
        num_ftrs = model.fc.in_features
        model.fc = nn.Linear(num_ftrs, NUM_CLASSES)
        
    else:
        raise ValueError(f"Model '{model_name}' is not supported in this example.")
    
    return model.to(DEVICE)

# --- 3. Data Transformations ---
# Standard transformations for ImageNet pretrained models.
# It's important to use the same normalization mean and std as the original training.
data_transforms = transforms.Compose([
    transforms.Resize(IMAGE_SIZE),       # Resize images to a consistent size
    transforms.CenterCrop(IMAGE_SIZE),   # Crop the center to the specified size
    transforms.ToTensor(),               # Convert PIL Image or numpy.ndarray to tensor
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]) # Normalize with ImageNet stats
])

# --- Main Script ---
if __name__ == "__main__":
    print(f"Using device: {DEVICE}")
    os.makedirs('pretrained_models_cache', exist_ok=True) # Ensure cache directory exists

    # Load and prepare the pretrained model with a new classification head
    model = load_and_modify_pretrained_model(model_name="resnet18")
    print(f"Model {model.__class__.__name__} prepared with new classification head for {NUM_CLASSES} classes.")

    # Create dummy datasets and dataloaders for training and validation
    print("Creating dummy datasets...")
    train_dataset = CustomImageDataset(num_samples=200, transform=data_transforms)
    val_dataset = CustomImageDataset(num_samples=50, transform=data_transforms)

    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True)
    val_loader = DataLoader(val_dataset, batch_size=BATCH_SIZE, shuffle=False)
    print(f"Train dataset size: {len(train_dataset)}, Validation dataset size: {len(val_dataset)}")

    # Define Loss Function and Optimizer
    criterion = nn.CrossEntropyLoss()
    # Fine-tune the entire model. For more granular control, you can define different
    # learning rates for different parameter groups (e.g., feature extractor vs. classifier head).
    optimizer = optim.Adam(model.parameters(), lr=LEARNING_RATE)
    
    # --- 4. Fine-tuning Loop ---
    print("\nStarting fine-tuning...")
    best_val_accuracy = 0.0
    model_save_path = "best_finetuned_model.pth"

    for epoch in range(NUM_EPOCHS):
        model.train() # Set model to training mode
        running_loss = 0.0
        correct_predictions = 0
        total_samples = 0

        for batch_idx, (inputs, labels) in enumerate(train_loader):
            inputs, labels = inputs.to(DEVICE), labels.to(DEVICE)

            optimizer.zero_grad() # Zero the parameter gradients
            outputs = model(inputs) # Forward pass
            loss = criterion(outputs, labels) # Calculate loss
            loss.backward() # Backward pass (compute gradients)
            optimizer.step() # Optimizer step (update model parameters)

            running_loss += loss.item() * inputs.size(0)
            _, predicted = torch.max(outputs.data, 1) # Get the class with the highest score
            total_samples += labels.size(0)
            correct_predictions += (predicted == labels).sum().item()

            if (batch_idx + 1) % 10 == 0: # Print progress every 10 batches
                print(f"Epoch [{epoch+1}/{NUM_EPOCHS}], Batch [{batch_idx+1}/{len(train_loader)}], "
                      f"Loss: {loss.item():.4f}")

        epoch_loss = running_loss / len(train_dataset)
        epoch_accuracy = correct_predictions / total_samples
        print(f"Epoch {epoch+1} Training Loss: {epoch_loss:.4f}, Training Accuracy: {epoch_accuracy:.4f}")

        # Validation phase
        model.eval() # Set model to evaluation mode
        val_loss = 0.0
        val_correct_predictions = 0
        val_total_samples = 0

        with torch.no_grad(): # Disable gradient calculations during validation
            for inputs, labels in val_loader:
                inputs, labels = inputs.to(DEVICE), labels.to(DEVICE)
                outputs = model(inputs)
                loss = criterion(outputs, labels)

                val_loss += loss.item() * inputs.size(0)
                _, predicted = torch.max(outputs.data, 1)
                val_total_samples += labels.size(0)
                val_correct_predictions += (predicted == labels).sum().item()

        val_epoch_loss = val_loss / len(val_dataset)
        val_epoch_accuracy = val_correct_predictions / val_total_samples
        print(f"Epoch {epoch+1} Validation Loss: {val_epoch_loss:.4f}, Validation Accuracy: {val_epoch_accuracy:.4f}")

        # Save the model if it has the best validation accuracy so far
        if val_epoch_accuracy > best_val_accuracy:
            best_val_accuracy = val_epoch_accuracy
            torch.save(model.state_dict(), model_save_path)
            print(f"Saved best model to {model_save_path} with accuracy: {best_val_accuracy:.4f}")

    print("\nFine-tuning complete!")
    print(f"Best validation accuracy achieved: {best_val_accuracy:.4f}")

    # --- Example of loading the fine-tuned model for inference ---
    print("\nLoading the best fine-tuned model for demonstration...")
    
    # First, instantiate the model architecture *identical to the one saved*.
    # This means creating `resnet18` and then replacing its `fc` layer.
    inference_model_architecture = models.resnet18(weights=None)
    num_ftrs = inference_model_architecture.fc.in_features
    inference_model_architecture.fc = nn.Linear(num_ftrs, NUM_CLASSES)
    inference_model_architecture.to(DEVICE)

    if os.path.exists(model_save_path):
        # Load the saved state_dict into the identical architecture.
        inference_model_architecture.load_state_dict(torch.load(model_save_path, map_location=DEVICE))
        inference_model_architecture.eval() # Set to evaluation mode
        print(f"Successfully loaded fine-tuned model from {model_save_path}")

        # You can now use `inference_model_architecture` for making predictions on new data.
        # Example: Pass a single dummy image through it
        dummy_input = torch.randn(1, 3, IMAGE_SIZE, IMAGE_SIZE).to(DEVICE) # Batch size of 1
        with torch.no_grad():
            output = inference_model_architecture(dummy_input)
        print(f"Example inference output shape: {output.shape} (logits for {NUM_CLASSES} classes)")
        predicted_class = torch.argmax(output, dim=1).item()
        print(f"Example predicted class: {predicted_class}")
    else:
        print(f"No fine-tuned model checkpoint found at {model_save_path} to load.")